import React from "react";
import AddTodoModal from "./AddTodoModal";import { ToastContainer, toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import moment from "moment/moment"
const Todo = ({todo}) => {
    return(
        <div>
           <div className="card text-white bg-secondary mb-3" style={{"maxWidth":"20rem"}}>

                <div className="card-body">
                    <h4 className="card-title">{todo.title}</h4>
                    <p className="card-text">{todo.description}</p>
                    <p className="card-text">{moment(todo.createdAt).fromNow()}</p>
                    <div className="actionButtons">
                    <button type="button" className="btn btn-primary">Primary</button>
                    </div>
                </div>
            </div>
            <div className = "" style={{ position: "fixed", right: 50,  bottom: 50, zIndex: 1000}}>
                <button type="button" className="btn btn-secondary" data-bs-toggle="modal" data-bs-target="#exampleModal">Add Todo</button>
            </div>
            <AddTodoModal />
            <ToastContainer
                position="top-right"
                autoClose={1500}
                hideProgressBar={false}
                newestOnTop={false}
                closeOnClick
                rtl={false}
                pauseOnFocusLoss
                draggable
                pauseOnHover
            />
        </div>    
    )
}

export default Todo;
